SELECT ?decade (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P56008 ?data_collection .

    ?venue rdfs:label ?venue_name .
    ?data_collection rdfs:label ?dc_label ;
                     orkgp:DATA ?research_data .

    ?research_data orkgp:P7055 ?data_type ;
                   orkgp:url ?url .

    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?decade
ORDER BY ?decade

SELECT ?paper ?paperLabel
       (COUNT(DISTINCT ?subquestion) AS ?subquestionCount)
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?serie .

    OPTIONAL {
        ?serie rdfs:label ?venue_name .
    }
    OPTIONAL {
        ?paper rdfs:label ?paperLabel .
    }

    OPTIONAL {
        ?contribution orkgp:P37330 ?researchQuestion .
        ?researchQuestion orkgp:P57000 ?subquestion .
    }

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY DESC(?subquestionCount) ?paperLabel

ASK {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:P181031 ?annotationProcess .
    ?annotationProcess orkgp:P181041 ?annotatorAgreement .
    ?annotatorAgreement rdfs:label ?annotatorAgreementLabel .

    FILTER(LCASE(STR(?annotatorAgreementLabel)) != "not reported")

    FILTER NOT EXISTS {
        ?annotatorAgreement orkgp:P181042 ?metric .
        ?metric rdfs:label ?metricLabel .
        FILTER(LCASE(STR(?metricLabel)) != "not reported")
    }

    FILTER NOT EXISTS {
        ?annotatorAgreement orkgp:P181044 ?conflictResolution .
        ?conflictResolution rdfs:label ?conflictResolutionLabel .
        FILTER(LCASE(STR(?conflictResolutionLabel)) != "not reported")
    }
}

SELECT ?coverage_class ?paper ?paperLabel ?validity_coverage_score
WHERE {
  {
    SELECT ?paper ?paperLabel (COUNT(DISTINCT ?category) AS ?validity_coverage_score)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      OPTIONAL { ?paper rdfs:label ?paperLabel . }

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

      ?venue rdfs:label ?venue_name .

      OPTIONAL {
        ?contribution orkgp:P39099 ?threats .

        {
          ?threats orkgp:P55037 ?v .
          BIND("construct validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55035 ?v .
          BIND("internal validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55034 ?v .
          BIND("external validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55036 ?v .
          BIND("conclusion validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P59109 ?v .
          BIND("reliability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P60006 ?v .
          BIND("generalizability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97002 ?v .
          BIND("repeatability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P68005 ?v .
          BIND("content validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97000 ?v .
          BIND("descriptive validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97001 ?v .
          BIND("theoretical validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P145000 ?v .
          BIND("mentioned"^^xsd:string AS ?category)
        }
      }

      FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    }
    GROUP BY ?paper ?paperLabel
  }

  BIND(
    IF(?validity_coverage_score = 0, "0"^^xsd:string,
      IF(?validity_coverage_score >= 1 && ?validity_coverage_score <= 2, "1–2"^^xsd:string,
        IF(?validity_coverage_score >= 3 && ?validity_coverage_score <= 4, "3–4"^^xsd:string,
          "5+"^^xsd:string
        )
      )
    ) AS ?coverage_class
  )
}
ORDER BY ?coverage_class DESC(?validity_coverage_score) ?paperLabel

SELECT ?research_paradigm ?research_paradigmLabel
       (COUNT(DISTINCT ?paper) AS ?total_papers)
       (SUM(?has_rqa_highlighted) AS ?papers_with_rqa_highlighted)
       ((100.0 * SUM(?has_rqa_highlighted)) / COUNT(DISTINCT ?paper) AS ?percentage_with_rqa_highlighted)
WHERE {
    {
        SELECT ?paper ?research_paradigm ?research_paradigmLabel
               (MAX(?rqa_highlighted_flag) AS ?has_rqa_highlighted)
        WHERE {
            ?paper orkgp:P31 ?contribution .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm .

            ?venue rdfs:label ?venue_name .

            OPTIONAL { ?research_paradigm rdfs:label ?research_paradigmLabel . }

            OPTIONAL {
                ?contribution orkgp:P57004 ?research_question_answer .
                ?research_question_answer orkgp:P55039 ?rqa_highlighted_in_text .
                BIND(1 AS ?rqa_highlighted_flag)
            }


            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?research_paradigm ?research_paradigmLabel
    }
}
GROUP BY ?research_paradigm ?research_paradigmLabel
ORDER BY DESC(?percentage_with_rqa_highlighted) ?research_paradigmLabel

SELECT DISTINCT ?dataset ?datasetLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  OPTIONAL { ?dataset rdfs:label ?datasetLabel . }
}
ORDER BY ?datasetLabel

SELECT ?year (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper orkgp:P31 ?contribution ;
           orkgp:P29 ?year .

    ?contribution a orkgc:C27001 ;
                  orkgp:P135046 ?venue ;
                  orkgp:P37330 ?research_question .

    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year
ORDER BY ?year

SELECT
  ?reTask
  ?reTaskLabel
  ?nlpTaskInput
  ?nlpTaskInputLabel
  ?outputType
  ?outputTypeLabel
  (COUNT(DISTINCT ?paper) AS ?paperCount)
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181002 ?reTask ;
                orkgp:P181003 ?nlpTask .

  ?nlpTask orkgp:P181005 ?nlpTaskInput ;
           orkgp:P181006 ?nlpTaskOutput .

  ?nlpTaskOutput orkgp:P181007 ?outputType .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
  OPTIONAL { ?nlpTaskInput rdfs:label ?nlpTaskInputLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
GROUP BY
  ?reTask ?reTaskLabel
  ?nlpTaskInput ?nlpTaskInputLabel
  ?outputType ?outputTypeLabel
ORDER BY ?reTaskLabel DESC(?paperCount) ?nlpTaskInputLabel ?outputTypeLabel
